                text = "*(She helps you up, and for the first time since the slab, the grave-priest looks less like your warden and more like your friend.)* The skips are getting longer, Returned. I have read enough requiems to know a countdown when I feel one. Whatever you are — the city in the sky is calling it home. Let us reach Candlekeep before the next pull takes you all the way.",
                onEnter = new[] { new FlagClause { key = "act1.complete", op = FlagOp.SetTrue }, new FlagClause { key = "act2.candlekeep_bound", op = FlagOp.SetTrue } },
            });

            Act1SkipDialogue = g;
        }
    }
}
